  wire [1:0] in1;
  (* src = "test.v:1.42-1.45" *)
  input [1:0] in2;
  wire [1:0] in2;
  (* src = "test.v:1.60-1.63" *)
  output [3:0] out;
  wire [3:0] out;
  NOT _14_ (
    .A(in1[0]),
    .Y(_12_)
  );
  NOT _15_ (
    .A(in2[0]),
    .Y(_13_)
  );
  NAND _16_ (
    .A(in1[1]),
    .B(in2[1]),
    .Y(_00_)
  );
  NOT _17_ (
    .A(_00_),
    .Y(_01_)
  );
  NOR _18_ (
    .A(_12_),
    .B(_13_),
    .Y(_02_)
  );
  NAND _19_ (
    .A(in1[0]),
    .B(in2[0]),
    .Y(_03_)
  );
  NOR _20_ (
