    .B(_07_),
    .Y(_08_)
  );
  NAND _25_ (
    .A(_02_),
    .B(_06_),
    .Y(_09_)
  );
  NAND _26_ (
    .A(_00_),
    .B(_09_),
    .Y(out[2])
  );
  NOR _27_ (
    .A(_02_),
    .B(_06_),
    .Y(_10_)
  );
  NOR _28_ (
    .A(_08_),
    .B(_10_),
    .Y(out[1])
  );
  NOR _29_ (
    .A(in1[0]),
    .B(in2[0]),
    .Y(_11_)
  );
  NOR _30_ (
    .A(_02_),
    .B(_11_),
    .Y(out[0])
  );
  assign out[3] = 1'h0;
endmodule
```

library.v
```
module BUF(A, Y);
input A;
output Y;
assign Y = A;
endmodule

module NOT(A, Y);
input A;
output Y;
assign Y = ~A;
endmodule

module NAND(A, B, Y);
input A, B;
output Y;
assign Y = ~(A & B);
endmodule

module NOR(A, B, Y);
input A, B;
output Y;
assign Y = ~(A | B);
endmodule

module DFF(C, D, Q);
input C, D;
output reg Q;
always @(posedge C)
	Q <= D;
endmodule

module DFFSR(C, D, Q, S, R);
input C, D, S, R;
output reg Q;
always @(posedge C, posedge S, posedge R)
	if (S)
		Q <= 1'b1;
	else if (R)
		Q <= 1'b0;
	else
		Q <= D;
endmodule
```

Run `circt-verilog` command:
```
circt-verilog netlist.v --l library.v
```

The tool reports an `unkonwn module xxx` error:
```
netlist.v:29:3: error: unknown module 'NOT'
  NOT _14_ (
  ^
netlist.v:33:3: error: unknown module 'NOT'
  NOT _15_ (
  ^
netlist.v:37:3: error: unknown module 'NAND'

......
```

**Root Cause**
I investigated the code and believe I found the cause of the issue.
In `circt/lib/Conversion/ImportVerilog/ImportVerilog.cpp`, inside the `circt::ImportDriver::prepareDriver` function, the` libraryFiles` from `ImportVerilogOptions` do not appear to be passed to the` slang::driver::Driver instance`.
Specifically, while `sourceFiles` are processed, the `options.libraryFiles` seem to be missing from the configuration step for the Slang driver. This prevents the specified library files from being included during compilation.

**Relevant Code Location**
File: `circt/lib/Conversion/ImportVerilog/ImportVerilog.cpp`
Function: `circt::ImportDriver::prepareDriver`

